/**
 * TransitionEngine — Sistema de transições entre slides
 *
 * Suporta fade, slideLeft, slideRight, slideUp, slideDown,
 * zoom, dissolve, wipe, wipeLeft, none.
 *
 * Todas as funções de easing e cálculo são **puras** (sem side-effects),
 * exportadas para testes unitários.
 */

// ============================================================================
// TYPES
// ============================================================================

/** Every supported transition type */
export type TransitionType =
  | 'none'
  | 'fade'
  | 'slideLeft'
  | 'slideRight'
  | 'slideUp'
  | 'slideDown'
  | 'zoom'
  | 'dissolve'
  | 'wipe'
  | 'wipeLeft';

/** A single transition preset definition */
export interface TransitionPreset {
  type: TransitionType;
  label: string;
  /** Short human-readable description */
  description: string;
  /** Default duration in seconds */
  defaultDuration: number;
  /** Category for grouping in the UI */
  category: 'basic' | 'slide' | 'advanced';
  /** Icon hint (lucide icon name) */
  icon: string;
}

/** Transition config attached to a scene */
export interface TransitionConfig {
  type: TransitionType;
  /** Duration in seconds (0.3 – 2.0) */
  duration: number;
}

