// ============================================================================
// PURE UTILITY FUNCTIONS
// ============================================================================

/**
 * Clamp a value between min and max.
 */
export function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

/**
 * Clamp a transition duration to the valid range.
 */
export function clampDuration(duration: number): number {
  if (duration <= 0) return 0;
  return clamp(duration, MIN_DURATION, MAX_DURATION);
}

/**
 * Ease-in-out cubic (smooth acceleration + deceleration).
 */
export function easeInOutCubic(t: number): number {
  const clamped = clamp(t, 0, 1);
  return clamped < 0.5
    ? 4 * clamped * clamped * clamped
    : 1 - Math.pow(-2 * clamped + 2, 3) / 2;
}

/**
 * Ease-out cubic (deceleration).
 */
export function easeOutCubic(t: number): number {
  const clamped = clamp(t, 0, 1);
  return 1 - Math.pow(1 - clamped, 3);
}

/**
 * Ease-in cubic (acceleration).
 */
export function easeInCubic(t: number): number {
  const clamped = clamp(t, 0, 1);
  return clamped * clamped * clamped;
}

/**
 * Linear interpolation.
 */
export function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * clamp(t, 0, 1);
}

/**
 * Compute raw progress (0→1) of a transition given current frame info.
 * `isExit` determines if we're computing exit (outgoing) vs entry (incoming).
 */
export function computeTransitionProgress(
  currentFrame: number,
  totalFrames: number,
  transitionFrames: number,
  isExit: boolean,
): number {
  if (transitionFrames <= 0 || totalFrames <= 0) return 1;
  const clampedTF = Math.min(transitionFrames, totalFrames);

  if (isExit) {
    // Exit: progress goes 1→0 in the last `transitionFrames` frames
    const exitStart = totalFrames - clampedTF;
    if (currentFrame < exitStart) return 1;
    const raw = (currentFrame - exitStart) / clampedTF;
    return 1 - clamp(raw, 0, 1);
  }
  // Entry: progress goes 0→1 in the first `transitionFrames` frames
  if (currentFrame >= clampedTF) return 1;
  return clamp(currentFrame / clampedTF, 0, 1);
}

/**
 * Get the preset object for a given type, fallback to 'none'.
 */
export function getPreset(type: TransitionType): TransitionPreset {
  return TRANSITION_PRESETS.find((p) => p.type === type) ?? TRANSITION_PRESETS[0];
}

/**
 * Get presets grouped by category.
 */
export function getPresetsByCategory(): Record<string, TransitionPreset[]> {
  const groups: Record<string, TransitionPreset[]> = {};
  for (const p of TRANSITION_PRESETS) {
    if (!groups[p.category]) {
      groups[p.category] = [];
    }
    groups[p.category].push(p);
  }
  return groups;
}

/**
 * Build a valid TransitionConfig, clamping duration.
 */
export function buildTransitionConfig(
  type: TransitionType,
  duration?: number,
): TransitionConfig {
  const preset = getPreset(type);
  if (type === 'none') {
    return { type: 'none', duration: 0 };
  }
  const d = duration ?? preset.defaultDuration;
  return { type, duration: clampDuration(d) };
}

/**
 * Validate whether a given string is a valid TransitionType.
 */
export function isValidTransitionType(value: string): value is TransitionType {
  return TRANSITION_PRESETS.some((p) => p.type === value);
}

/**
 * Get the category label for a category key.
 */
export function getCategoryLabel(category: string): string {
  switch (category) {
    case 'basic':
      return 'Básicas';
    case 'slide':
      return 'Deslizamento';
    case 'advanced':
      return 'Avançadas';
    default:
      return category;
  }
}

/**
 * Map legacy transition strings (from Scene type) to TransitionType.
 * Handles backwards compatibility.
 */
export function normalizeLegacyTransition(value: string): TransitionType {
  const map: Record<string, TransitionType> = {
    fade: 'fade',
    slide: 'slideLeft',
    zoom: 'zoom',
    none: 'none',
    dissolve: 'dissolve',
    wipe: 'wipe',
    wipeLeft: 'wipeLeft',
    slideLeft: 'slideLeft',
    slideRight: 'slideRight',
    slideUp: 'slideUp',
    slideDown: 'slideDown',
  };
  return map[value] ?? 'none';
}

/**
 * Compute CSS-like transform/opacity values for a given transition at progress t.
 * Returns an object suitable for applying as React inline styles.
 * Used for the preview animations in the TransitionPicker.
 */
export function computeTransitionStyle(
  type: TransitionType,
  progress: number,
  width: number,
  height: number,
): { opacity: number; transform: string } {
  const p = easeInOutCubic(clamp(progress, 0, 1));

  switch (type) {
    case 'none':
      return { opacity: 1, transform: 'none' };

    case 'fade':
      return { opacity: p, transform: 'none' };

    case 'dissolve':
      // Dissolve = fade with slight scale
      return {
        opacity: p,
        transform: `scale(${lerp(1.02, 1, p)})`,
      };

    case 'slideLeft':
      return {
        opacity: 1,
        transform: `translateX(${lerp(width, 0, p)}px)`,
      };

    case 'slideRight':
      return {
        opacity: 1,
        transform: `translateX(${lerp(-width, 0, p)}px)`,
      };

    case 'slideUp':
      return {
        opacity: 1,
        transform: `translateY(${lerp(height, 0, p)}px)`,
      };

    case 'slideDown':
      return {
        opacity: 1,
        transform: `translateY(${lerp(-height, 0, p)}px)`,
      };

    case 'zoom':
      return {
        opacity: p,
        transform: `scale(${lerp(0.7, 1, p)})`,
      };

    case 'wipe': {
      // Wipe right: clip from left
      const clipX = lerp(width, 0, p);
      return {
        opacity: 1,
        transform: `translateX(0)`,
      };
      // Note: wipe effect needs clipPath, handled separately in preview
      void clipX;
    }

    case 'wipeLeft': {
      const clipX = lerp(0, width, p);
      return {
        opacity: 1,
        transform: `translateX(0)`,
      };
      void clipX;
    }

    default:
      return { opacity: 1, transform: 'none' };
  }
}

/**
 * Compute clipPath polygon for wipe-style transitions.
 * Returns a CSS `clip-path` value or undefined if not applicable.
 */
export function computeWipeClipPath(
  type: TransitionType,
  progress: number,
): string | undefined {
  const p = easeInOutCubic(clamp(progress, 0, 1));
  const pct = Math.round(p * 100);

  switch (type) {
    case 'wipe':
      // Reveal from left to right
      return `inset(0 ${100 - pct}% 0 0)`;

    case 'wipeLeft':
      // Reveal from right to left
      return `inset(0 0 0 ${100 - pct}%)`;

    default:
      return undefined;
  }
}

/**
 * Generate FFmpeg filter expression for a transition between two segments.
 * Returns the xfade filter string for use in complex filter graphs.
 */
export function generateFFmpegTransitionFilter(
  type: TransitionType,
  duration: number,
  offsetSeconds: number,
): string {
  const d = clampDuration(duration);
  if (type === 'none' || d <= 0) return '';

  // Map our types to FFmpeg xfade transition names
  const ffmpegMap: Record<TransitionType, string> = {
    none: '',
    fade: 'fade',
    dissolve: 'dissolve',
    slideLeft: 'slideleft',
    slideRight: 'slideright',
    slideUp: 'slideup',
    slideDown: 'slidedown',
    zoom: 'smoothup',
    wipe: 'wiperight',
    wipeLeft: 'wipeleft',
  };

  const ffName = ffmpegMap[type];
  if (!ffName) return '';

  return `xfade=transition=${ffName}:duration=${d}:offset=${offsetSeconds}`;
}

/**
 * Compute total project duration accounting for transition overlaps.
 * Each transition causes the adjacent scenes to overlap by `transition.duration` seconds.
 */
export function computeTotalDurationWithTransitions(
  sceneDurations: number[],
  transitions: TransitionConfig[],
): number {
  if (sceneDurations.length === 0) return 0;

  let total = sceneDurations[0];
  for (let i = 1; i < sceneDurations.length; i++) {
    const t = transitions[i - 1];
    const overlap = t && t.type !== 'none' ? t.duration : 0;
    total += sceneDurations[i] - overlap;
  }
  return Math.max(0, total);
}

/**
 * Build the full FFmpeg filter chain for a sequence of scenes with transitions.
 * Returns an array of filter strings to be joined in a complex filtergraph.
 */
export function buildFFmpegFilterChain(
  sceneDurations: number[],
  transitions: TransitionConfig[],
): string[] {
  const filters: string[] = [];
  let cumulativeOffset = 0;

  for (let i = 0; i < sceneDurations.length - 1; i++) {
    const t = transitions[i] ?? { type: 'none' as const, duration: 0 };
    const overlap = t.type !== 'none' ? t.duration : 0;
    cumulativeOffset += sceneDurations[i] - overlap;

    const filter = generateFFmpegTransitionFilter(
      t.type,
      t.duration,
      cumulativeOffset - (sceneDurations[i] - overlap) + sceneDurations[i] - overlap,
    );
    if (filter) {
      filters.push(filter);
    }
  }

  return filters;
}

/**
 * Serialize a TransitionConfig to a compact string (for storage/URL).
 */
export function serializeTransition(config: TransitionConfig): string {
  if (config.type === 'none') return 'none';
  return `${config.type}:${config.duration}`;
}

/**
 * Deserialize a compact transition string back to TransitionConfig.
 */
export function deserializeTransition(str: string): TransitionConfig {
  if (!str || str === 'none') {
    return { type: 'none', duration: 0 };
  }
  const [typeStr, durStr] = str.split(':');
  const type = isValidTransitionType(typeStr) ? typeStr : 'none';
  const duration = durStr ? parseFloat(durStr) : getPreset(type).defaultDuration;
  return buildTransitionConfig(type, isNaN(duration) ? undefined : duration);
}
